            if p == "inaugurationDate":
                return f"was inaugurated on {obj}"
            if p == "birthPlace":
                return f"was born in {obj}"
            if p == "deathPlace":
                return f"died in {obj}"
            if p == "bedCount":
                return f"has {obj} beds"
            if p == "region":
