            if p == "leaderTitle":
                return f"is led via the {obj}"
            if p == "currency":
                return f"the currency is {obj}"
            if p == "ethnicGroup":
                return f"the main ethnic group is {obj}"
            if p == "origin":
                return f"{obj} is the hometown of {subject}"
            if p == "significantProject":
                return f"is known for the project {obj}"
            if p == "foundationPlace":
