            if not sentence_body.lower().startswith(subject.lower()):
                sentence = f"{subject} {sentence_body}."
            else:
                sentence = sentence_body + "."
        else:
            sentence = f"{subject}."

        sentences.append(sentence)

    final_text = " ".join(sentences)
